// Program outline imports SVGs (primarily those generated by KiCad)
// and converts them into polygon.Shapes that outline the overlapping
// input data. It outputs in the form of a gnuplot inline script.
package main

import (
	"flag"
	"fmt"
	"io"
	"log"
	"os"
	"strings"

	"zappem.net/pub/graphics/svger"
	"zappem.net/pub/graphics/svgpoly"
	"zappem.net/pub/math/polygon"
)

var (
	src    = flag.String("svg", "", "input SVG file")
	dest   = flag.String("dest", "", "output gnuplot script filename")
	debug  = flag.Bool("debug", false, "enable more debugging output")
	before = flag.Bool("before", false, "show polygons before creating union")
	after  = flag.Bool("after", true, "show polygons after creating union")
	scribe = flag.Float64("scribe", 0.1, "pen scribing size (detail for rounding circles)")
)

// plotData outputs the polygon data into a gnuplot format.
func plotData(out io.Writer, s *polygon.Shapes) {
	if s == nil {
		log.Fatal("Unable to plot empty shapes")
	}
	fmt.Fprintln(out, "# X Y")
	for i, p := range s.P {
		for _, pt := range p.PS {
			fmt.Fprintf(out, "%g %g\n", pt.X, pt.Y)
		}
		fmt.Fprintf(out, "%g %g\n", p.PS[0].X, p.PS[0].Y)
		if i != len(s.P)-1 {
			fmt.Fprintln(out)
		}
	}
	fmt.Fprintln(out, "e")
}

func main() {
	log.Default().SetFlags(log.Lshortfile | log.Ldate | log.Lmicroseconds)
	flag.Parse()
	svger.Debug = *debug

	// shapes are closed (filled) polygons.
	// cuts are outlines with no substance.
	shapes, cuts, err := svgpoly.LoadSVG(*src, *scribe)
	if err != nil {
		log.Fatalf("Failed to load --svg=%q: %v", err)
	}

	haveShapes := *before && shapes != nil && len(shapes.P) != 0
	haveCuts := cuts != nil && len(cuts.P) != 0
	haveUnion := *after && shapes != nil && len(shapes.P) != 0

	var prefix []string
	if haveShapes {
		prefix = append(prefix, "'-' with lines title 'before'")
	}
	if haveCuts {
		prefix = append(prefix, "'-' with lines title 'cuts'")
	}
	if haveUnion {
		prefix = append(prefix, "'-' with lines title 'union'")
	}

	if len(prefix) == 0 {
		log.Fatal("nothing to display")
	}

	out := os.Stdout
	if *dest != "" {
		out, err = os.Create(*dest)
		if err != nil {
			log.Fatalf("Unable to generate output %q: %v", *dest, err)
		}
		defer out.Close()
	}

	fmt.Fprintf(out, "plot %s\n", strings.Join(prefix, ", \\\n     "))
	if haveShapes {
		plotData(out, shapes)
	}
	if haveCuts {
		plotData(out, cuts)
	}
	if haveUnion {
		shapes.Union()
		plotData(out, shapes)
	}
}
